static void secure_uart_init(void)
{
    /* Enable USART2 clock */
    RCC_APB2ENR |= (1UL << 17);  /* Adjust for your USART */

    /* Configure GPIO pins for UART TX/RX */
    /* (Platform-specific pin configuration) */

    /* Configure UART: 115200 baud, 8N1 */
    /* Assuming 16 MHz APB clock */
    USART_BRR(USART2_BASE) = 0x008B;  /* ~115200 baud at 16 MHz */

    /* Enable UART, TX, and RX */
    USART_CR1(USART2_BASE) = USART_CR1_UE | USART_CR1_TE | USART_CR1_RE;
}

static void secure_uart_send_char(char c)
{
    while (!(USART_SR(USART2_BASE) & USART_SR_TXE)) {}
    USART_DR(USART2_BASE) = (uint32_t)c;
}

static void secure_uart_send_string(const char *str)
{
    while (*str) {
        secure_uart_send_char(*str++);
    }
}

static void secure_uart_send_line(const char *str)
{
    secure_uart_send_string(str);
    secure_uart_send_string("\r\n");
}

static bool secure_uart_char_available(void)
{
    return (USART_SR(USART2_BASE) & USART_SR_RXNE) != 0;
}

static char secure_uart_read_char(void)
{
    while (!secure_uart_char_available()) {}
    return (char)(USART_DR(USART2_BASE) & 0xFF);
}

/* ============================================================
 * 3. AUTHENTICATION SYSTEM
 *    Challenge-response using HMAC-SHA256
 * ============================================================ */

static void session_start_challenge(void)
{
    if (g_session.state == SESSION_LOCKED_OUT) {
        uint32_t elapsed = g_system_tick - g_session.lockout_start_tick;
        if (elapsed < LOCKOUT_DURATION_SEC) {
            char buf[64];
            uint32_t remaining = LOCKOUT_DURATION_SEC - elapsed;
            secure_uart_send_string("LOCKED OUT. Try again in ");
            uint32_to_dec_string(remaining, buf, sizeof(buf));
            secure_uart_send_string(buf);
            secure_uart_send_line(" seconds.");
            return;
        }
        /* Lockout expired, reset */
        g_session.state = SESSION_NONE;
        g_session.auth_attempts = 0;
    }

    /* Generate random challenge */
    crypto_get_random_bytes((uint8_t *)g_session.challenge, CHALLENGE_LEN);
    g_session.state = SESSION_CHALLENGE_SENT;

    /* Send challenge as hex string */
    char hex_challenge[CHALLENGE_LEN * 2 + 1];
    hex_to_string(g_session.challenge, CHALLENGE_LEN, hex_challenge);

    secure_uart_send_string("CHALLENGE: ");
    secure_uart_send_line(hex_challenge);
    secure_uart_send_line("Respond with: auth <HMAC-SHA256 hex>");
}

static bool session_verify_response(const uint8_t *response, uint8_t len)
{
    if (len != HMAC_SHA256_LEN) {
        return false;
    }

    /*
     * The service technician's tool computes:
     *   HMAC-SHA256(shared_service_key, challenge)
     * and sends the result.
     *
     * The shared_service_key is stored securely in the device's
     * hardware security module or protected flash region.
     * It is NOT the same as any communication encryption key.
     */

    /* Retrieve service key from secure storage */
    /* This is a placeholder - use your HSM/secure element API */
    static const uint8_t service_key[] = {
        /* This would be provisioned per-device or per-fleet */
        0x00 /* placeholder */
    };

    return crypto_hmac_sha256_verify(
        service_key, sizeof(service_key),
        (const uint8_t *)g_session.challenge, CHALLENGE_LEN,
        response
    );
}

static bool session_is_authenticated(void)
{
    if (g_session.state != SESSION_AUTHENTICATED) {
        return false;
    }

    /* Check session timeout */
    uint32_t elapsed = g_system_tick - g_session.session_start_tick;
    if (elapsed > SESSION_TIMEOUT_SEC) {
        session_invalidate();
        secure_uart_send_line("Session expired. Re-authenticate.");
        return false;
    }

    return true;
}

static void session_check_timeout(void)
{
    if (g_session.state == SESSION_AUTHENTICATED) {
        uint32_t elapsed = g_system_tick - g_session.session_start_tick;
        if (elapsed > SESSION_TIMEOUT_SEC) {
            session_invalidate();
        }
    }
}

static void session_invalidate(void)
{
    memset((void *)&g_session, 0, sizeof(g_session));
    g_session.state = SESSION_NONE;
}

/* ============================================================
 * 4. SAFE DIAGNOSTIC COMMANDS
 *    These expose ONLY operational health data.
 *    NO memory dumps, NO flash reads, NO config extraction.
 * ============================================================ */

static void diag_process_command(const char *cmd)
{
    /* Commands available without authentication */
    if (strcmp(cmd, "help") == 0 || strcmp(cmd, "?") == 0) {
        diag_cmd_help();
        return;
    }

    if (strcmp(cmd, "version") == 0) {
        diag_cmd_version();
        return;
    }

    if (strcmp(cmd, "login") == 0) {
        session_start_challenge();
        return;
    }

    if (strncmp(cmd, "auth ", 5) == 0) {
        diag_cmd_auth(cmd + 5);
        return;
    }

    if (strcmp(cmd, "logout") == 0) {
        session_invalidate();
        secure_uart_send_line("Session ended.");
        return;
    }

    /* ---- Blocked dangerous commands with clear explanation ---- */
    if (strncmp(cmd, "dump_memory", 11) == 0 ||
        strncmp(cmd, "read_flash", 10) == 0 ||
        strncmp(cmd, "get_config", 10) == 0 ||
        strncmp(cmd, "write_mem", 9) == 0 ||
        strncmp(cmd, "read_mem", 8) == 0 ||
        strncmp(cmd, "dump", 4) == 0 ||
        strncmp(cmd, "peek", 4) == 0 ||
        strncmp(cmd, "poke", 4) == 0 ||
        strncmp(cmd, "jtag", 4) == 0 ||
        strncmp(cmd, "swd", 3) == 0 ||
        strncmp(cmd, "enable_debug", 12) == 0) {

        secure_uart_send_line("ERROR: Command blocked for security.");
        secure_uart_send_line("Memory/flash/config access is not available");
        secure_uart_send_line("on production devices. Use safe diagnostics:");
        secure_uart_send_line("  health, sensor, network, errors, selftest");
        return;
    }

    /* ---- All remaining commands require authentication ---- */
    if (!session_is_authenticated()) {
        secure_uart_send_line("Authentication required. Type 'login' first.");
        return;
    }

    if (strcmp(cmd, "health") == 0) {
        diag_cmd_health();
    } else if (strncmp(cmd, "sensor", 6) == 0) {
        uint8_t id = 0;
        if (cmd[6] == ' ' && cmd[7] >= '0' && cmd[7] <= '3') {
            id = (uint8_t)(cmd[7] - '0');
        }
        diag_cmd_sensor_status(id);
    } else if (strcmp(cmd, "network") == 0) {
        diag_cmd_network_status();
    } else if (strcmp(cmd, "errors") == 0) {
        diag_cmd_error_log();
    } else if (strcmp(cmd, "clear_errors") == 0) {
        diag_cmd_clear_errors();
    } else if (strcmp(cmd, "selftest") == 0) {
        diag_cmd_self_test();
    } else if (strcmp(cmd, "uptime") == 0) {
        diag_cmd_uptime();
    } else if (strcmp(cmd, "restart") == 0) {
        diag_cmd_restart();
    } else if (strcmp(cmd, "factory_reset") == 0) {
        diag_cmd_factory_reset();
    } else {
        secure_uart_send_string("Unknown command: ");
        secure_uart_send_line(cmd);
        secure_uart_send_line("Type 'help' for available commands.");
    }
}

