static void diag_cmd_auth(const char *response)
{
    if (g_session.state != SESSION_CHALLENGE_SENT) {
        secure_uart_send_line("No pending challenge. Type 'login' first.");
        return;
    }

    uint8_t response_bytes[HMAC_SHA256_LEN];
    if (!hex_string_to_bytes(response, response_bytes, HMAC_SHA256_LEN)) {
        secure_uart_send_line("Invalid hex format.");
        g_session.auth_attempts++;
        if (g_session.auth_attempts >= MAX_AUTH_ATTEMPTS) {
            g_session.state = SESSION_LOCKED_OUT;
            g_session.lockout_start_tick = g_system_tick;
            secure_uart_send_line("Too many failed attempts. Locked out.");
        }
        return;
    }

    if (session_verify_response(response_bytes, HMAC_SHA256_LEN)) {
        g_session.state = SESSION_AUTHENTICATED;
        g_session.session_start_tick = g_system_tick;
        g_session.auth_attempts = 0;
        secure_uart_send_line("Authentication successful.");
        secure_uart_send_line("Session active. Type 'help' for commands.");
    } else {
        g_session.auth_attempts++;
        if (g_session.auth_attempts >= MAX_AUTH_ATTEMPTS) {
            g_session.state = SESSION_LOCKED_OUT;
            g_session.lockout_start_tick = g_system_tick;
            secure_uart_send_line("Authentication failed. Account locked.");

            /* Log failed auth attempt */
            error_log_entry_t entry = {0};
            entry.timestamp = g_system_tick;
            entry.error_code = 0xDEAD0002;
            entry.severity = DIAG_WARNING;
            strncpy(entry.module, "AUTH", sizeof(entry.module) - 1);
            strncpy(entry.message, "Max auth attempts exceeded - lockout", sizeof(entry.message) - 1);
            g_error_log[g_error_log_index % ERROR_LOG_MAX_ENTRIES] = entry;
            g_error_log_index++;
        } else {
            char buf[16];
            secure_uart_send_string("Authentication failed. Attempts remaining: ");
            uint32_to_dec_string(MAX_AUTH_ATTEMPTS - g_session.auth_attempts, buf, sizeof(buf));
            secure_uart_send_line(buf);
        }
    }
}

