static void diag_cmd_error_log(void)
{
    char buf[32];
    uint8_t count = (g_error_log_index < ERROR_LOG_MAX_ENTRIES) ?
                     g_error_log_index : ERROR_LOG_MAX_ENTRIES;

    secure_uart_send_line("=== Error Log ===");

    if (count == 0) {
        secure_uart_send_line("No errors recorded.");
        return;
    }

    secure_uart_send_string("Entries: ");
    uint32_to_dec_string(count, buf, sizeof(buf));
    secure_uart_send_line(buf);
    secure_uart_send_line("");

    for (uint8_t i = 0; i < count; i++) {
        error_log_entry_t *e = &g_error_log[i];

        secure_uart_send_string("[");
        uint32_to_dec_string(e->timestamp, buf, sizeof(buf));
        secure_uart_send_string(buf);
        secure_uart_send_string("] ");

        switch (e->severity) {
            case DIAG_INFO:     secure_uart_send_string("INFO "); break;
            case DIAG_WARNING:  secure_uart_send_string("WARN "); break;
            case DIAG_ERROR:    secure_uart_send_string("ERR  "); break;
            case DIAG_CRITICAL: secure_uart_send_string("CRIT "); break;
            default:            secure_uart_send_string("???? "); break;
        }

        secure_uart_send_string(e->module);
        secure_uart_send_string(": ");
        secure_uart_send_line(e->message);
    }
}

