static void diag_cmd_self_test(void)
{
    secure_uart_send_line("=== Running Self-Test ===");

    /* Test 1: CPU */
    secure_uart_send_string("CPU............");
    /* Basic arithmetic check */
    volatile uint32_t a = 0xDEADBEEF;
    volatile uint32_t b = 0x12345678;
    volatile uint32_t c = a + b;
    if (c == 0xF1E21567UL) {
        secure_uart_send_line("PASS");
    } else {
        secure_uart_send_line("FAIL");
    }

    /* Test 2: RAM */
    secure_uart_send_string("RAM............");
    volatile uint32_t ram_test = 0;
    ram_test = 0xA5A5A5A5;
    if (ram_test == 0xA5A5A5A5) {
        ram_test = 0x5A5A5A5A;
        if (ram_test == 0x5A5A5A5A) {
            secure_uart_send_line("PASS");
        } else {
            secure_uart_send_line("FAIL");
        }
    } else {
        secure_uart_send_line("FAIL");
    }

    /* Test 3: Sensors */
    for (uint8_t i = 0; i < 4; i++) {
        char buf[4];
        secure_uart_send_string("Sensor ");
        uint32_to_dec_string(i, buf, sizeof(buf));
        secure_uart_send_string(buf);
        secure_uart_send_string("......");
        if (g_sensor_status[i].sensor_online) {
            secure_uart_send_line("PASS");
        } else {
            secure_uart_send_line("OFFLINE");
        }
    }

    /* Test 4: Network */
    secure_uart_send_string("Network........");
    secure_uart_send_line(g_network_diag.connected ? "PASS" : "FAIL");

    /* Test 5: Security lockdown */
    secure_uart_send_string("Security.......");
    uint32_t dbg_cr = DBGMCU_CR;
    if ((dbg_cr & (DBGMCU_CR_DBG_SLEEP | DBGMCU_CR_DBG_STOP |
                   DBGMCU_CR_DBG_STANDBY | DBGMCU_CR_TRACE_EN)) == 0) {
        secure_uart_send_line("PASS");
    } else {
        secure_uart_send_line("FAIL - Debug not locked!");
        security_lockdown_jtag_swd();
    }

    secure_uart_send_line("=== Self-Test Complete ===");
}

