static void diag_cmd_restart(void)
{
    secure_uart_send_line("Restarting device...");

    /* Small delay for UART to flush */
    volatile uint32_t delay = 100000;
    while (delay--) { __asm volatile("nop"); }

    /* Trigger system reset via NVIC */
    /* SCB->AIRCR = (0x5FA << 16) | (1 << 2); */
    *((volatile uint32_t *)0xE000ED0CUL) = 0x05FA0004UL;

    /* Should not reach here */
    while (1) {}
}

