/* ============================================================
 * 5. UTILITY FUNCTIONS
 * ============================================================ */

static void uint32_to_dec_string(uint32_t val, char *buf, uint8_t buf_len)
{
    if (buf_len == 0) return;

    char tmp[11]; /* max 10 digits + null */
    uint8_t i = 0;

    if (val == 0) {
        if (buf_len >= 2) {
            buf[0] = '0';
            buf[1] = '\0';
        }
        return;
    }

    while (val > 0 && i < 10) {
        tmp[i++] = '0' + (char)(val % 10);
        val /= 10;
    }

    uint8_t j = 0;
    while (i > 0 && j < (buf_len - 1)) {
        buf[j++] = tmp[--i];
    }
    buf[j] = '\0';
}

static void int32_to_dec_string(int32_t val, char *buf, uint8_t buf_len)
{
    if (buf_len < 2) return;

    if (val < 0) {
        buf[0] = '-';
        uint32_to_dec_string((uint32_t)(-val), buf + 1, buf_len - 1);
    } else {
        uint32_to_dec_string((uint32_t)val, buf, buf_len);
    }
}

static void hex_to_string(const uint8_t *data, uint8_t len, char *out)
{
    static const char hex_chars[] = "0123456789abcdef";
    for (uint8_t i = 0; i < len; i++) {
        out[i * 2]     = hex_chars[(data[i] >> 4) & 0x0F];
        out[i * 2 + 1] = hex_chars[data[i] & 0x0F];
    }
    out[len * 2] = '\0';
}

static bool hex_string_to_bytes(const char *hex, uint8_t *out, uint8_t max_len)
{
    uint8_t i = 0;
    while (*hex && *(hex + 1) && i < max_len) {
        uint8_t hi, lo;
        char c = *hex++;
        if (c >= '0' && c <= '9') hi = (uint8_t)(c - '0');
        else if (c >= 'a' && c <= 'f') hi = (uint8_t)(c - 'a' + 10);
        else if (c >= 'A' && c <= 'F') hi = (uint8_t)(c - 'A' + 10);
        else return false;

        c = *hex++;
        if (c >= '0' && c <= '9') lo = (uint8_t)(c - '0');
        else if (c >= 'a' && c <= 'f') lo = (uint8_t)(c - 'a' + 10);
        else if (c >= 'A' && c <= 'F') lo = (uint8_t)(c - 'A' + 10);
        else return false;

        out[i++] = (hi << 4) | lo;
    }
    return (i == max_len);
}

