/* ============================================================
 * 7. MAIN DIAGNOSTIC LOOP
 * ============================================================ */

static void diag_uart_poll(void)
{
    if (!secure_uart_char_available()) {
        return;
    }

    char c = secure_uart_read_char();

    /* Echo character */
    if (c >= 0x20 && c < 0x7F) {
        secure_uart_send_char(c);
    }

    /* Handle backspace */
    if (c == 0x08 || c == 0x7F) {
        if (g_uart_rx_pos > 0) {
            g_uart_rx_pos--;
            secure_uart_send_string("\b \b");
        }
        return;
    }

    /* Handle enter */
    if (c == '\r' || c == '\n') {
        secure_uart_send_string("\r\n");

        if (g_uart_rx_pos > 0) {
            g_uart_rx_buf[g_uart_rx_pos] = '\0';
            diag_process_command(g_uart_rx_buf);
            g_uart_rx_pos = 0;
        }

        secure_uart_send_string(session_is_authenticated() ? "diag> " : "diag(locked)> ");
        return;
    }

    /* Buffer printable characters with overflow protection */
    if (c >= 0x20 && c < 0x7F && g_uart_rx_pos < (sizeof(g_uart_rx_buf) - 1)) {
        g_uart_rx_buf[g_uart_rx_pos++] = c;
    }
}

/* ============================================================
 * 8. INITIALIZATION AND MAIN
 * ============================================================ */

void diagnostic_system_init(void)
{
    /*
     * STEP 1: LOCK DOWN DEBUG INTERFACES FIRST
     * This must happen before anything else.
     */
    security_lockdown_jtag_swd();
    security_reconfigure_jtag_pins_as_gpio();
    security_disable_debug_peripherals();
    security_enable_flash_readout_protection();

    /*
     * STEP 2: Initialize secure UART console
     * This provides authenticated, limited diagnostics only.
     */
    secure_uart_init();

    /* Initialize session state */
    memset((void *)&g_session, 0, sizeof(g_session));

    /* Initialize health data with firmware version */
    g_health.firmware_major = 2;
    g_health.firmware_minor = 1;
    g_health.firmware_patch = 0;
    g_health.hw_revision = 3;

    /* Boot banner */
    secure_uart_send_line("");
    secure_uart_send_line("================================");
    secure_uart_send_line(" Industrial IoT Sensor v2.1.0");
    secure_uart_send_line(" Secure Field Diagnostics");
    secure_uart_send_line("================================");
    secure_uart_send_line("Type 'help' for commands.");
    secure_uart_send_line("Authentication required for diagnostics.");
    secure_uart_send_line("");
    secure_uart_send_string("diag(locked)> ");
}

void diagnostic_system_tick(void)
{
    /* Called from main loop or timer ISR */
    g_system_tick++;
    g_health.uptime_seconds = g_system_tick;  /* Assuming 1 Hz tick */

    /* Periodically verify security lockdown */
    if ((g_system_tick % 60) == 0) {
        security_verify_lockdown();
    }

    /* Check session timeout */
    session_check_timeout();

    /* Poll UART for commands */
    diag_uart_poll();
}

